class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        List<int[]>[] graph = new ArrayList[n];
        for (int i = 0; i < n; i++) {
            graph[i] = new ArrayList<>();
        }
        for (int[] edge : edges) {
            graph[edge[0]].add(new int[] {edge[1], edge[2], edge[3]});
            graph[edge[1]].add(new int[] {edge[0], edge[2], edge[3]});
        }
        int[] parent = new int[n];
        Arrays.fill(parent, -1);
        int[] minStrength = new int[n];
        Arrays.fill(minStrength, Integer.MAX_VALUE);
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[1] - b[1]);
        for (int i = 0; i < n; i++) {
            for (int[] neighbor : graph[i]) {
                if (neighbor[2] == 1) {
                    pq.offer(new int[] {i, neighbor[0], neighbor[1]});
                }
            }
        }
        while (!pq.isEmpty() && k > 0) {
            int[] edge = pq.poll();
            if (union(parent, edge[0], edge[1])) {
                minStrength[edge[1]] = Math.min(minStrength[edge[1]], edge[2]);
                k--;
            }
        }
        if (k > 0) {
            for (int i = 0; i < n; i++) {
                for (int[] neighbor : graph[i]) {
                    if (neighbor[2] == 0 && k > 0) {
                        pq.offer(new int[] {i, neighbor[0], neighbor[1]});
                        k--;
                    }
                }
            }
        }
        while (!pq.isEmpty()) {
            int[] edge = pq.poll();
            if (union(parent, edge[0], edge[1])) {
                minStrength[edge[1]] = Math.min(minStrength[edge[1]], edge[2]);
            }
        }
        int min = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            min = Math.min(min, minStrength[i]);
        }
        if (min == Integer.MAX_VALUE) {
            return -1;
        }
        return min;
    }

    private boolean union(int[] parent, int x, int y) {
        int rootX = find(parent, x);
        int rootY = find(parent, y);
        if (rootX != rootY) {
            parent[rootY] = rootX;
            return true;
        }
        return false;
    }

    private int find(int[] parent, int x) {
        if (parent[x] == -1) {
            return x;
        }
        return parent[x] = find(parent, parent[x]);
    }
}
